'use client';

import { useState } from 'react';
import { useAuth } from '../../context/AuthContext';
import { Settings, Lock, Trash2, Globe, Palette } from 'lucide-react';

export default function SettingsPage() {
  const { user, logout } = useAuth();
  const [oldPassword, setOldPassword] = useState('');
  const [newPassword, setNewPassword] = useState('');
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);

  const handlePasswordChange = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError('');
    setSuccess('');
    try {
      const res = await fetch('http://localhost:5000/api/user/password', {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ oldPassword, newPassword }),
        credentials: 'include'
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error);
      setSuccess("Password updated successfully");
      setOldPassword('');
      setNewPassword('');
    } catch (err: any) {
      setError(err.message);
    } finally {
      setIsLoading(false);
    }
  };

  const handleDeleteAccount = async () => {
    try {
      await fetch('http://localhost:5000/api/user', { method: 'DELETE', credentials: 'include' });
      logout();
    } catch (err) {
      console.error(err);
    }
  };

  if (!user) return <div className="p-8 text-center text-gray-400">Please log in to access settings.</div>;

  return (
    <div className="container" style={{ paddingTop: '4rem', maxWidth: '900px' }}>
      <div className="mb-12">
        <h1 className="text-5xl font-extrabold tracking-tight mb-3">Settings</h1>
        <p className="text-gray-400 text-lg">Manage your account preferences and security.</p>
      </div>
      
      <div className="grid gap-8">
        {/* Account Security */}
        <div className="glass-card">
          <div className="flex items-center gap-3 mb-8">
            <div className="p-2 bg-indigo-500/10 rounded-lg text-indigo-400">
              <Lock size={22} />
            </div>
            <div>
              <h2 className="text-xl font-bold">Security</h2>
              <p className="text-sm text-gray-400">Update your password to keep your account safe.</p>
            </div>
          </div>

          <form onSubmit={handlePasswordChange} className="space-y-4 max-w-md">
            {error && <div className="p-4 text-sm text-red-400 bg-red-400/5 border border-red-400/10 rounded-xl">{error}</div>}
            {success && <div className="p-4 text-sm text-green-400 bg-green-400/5 border border-green-400/10 rounded-xl">{success}</div>}
            
            <div className="space-y-2">
              <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider ml-1">Current Password</label>
              <input 
                type="password" placeholder="••••••••" required
                className="w-full bg-white/5 border border-white/5 rounded-xl px-4 py-3 text-white outline-none focus:ring-2 focus:ring-indigo-500/50 transition-all"
                value={oldPassword} onChange={e => setOldPassword(e.target.value)}
              />
            </div>
            
            <div className="space-y-2">
              <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider ml-1">New Password</label>
              <input 
                type="password" placeholder="••••••••" required
                className="w-full bg-white/5 border border-white/5 rounded-xl px-4 py-3 text-white outline-none focus:ring-2 focus:ring-indigo-500/50 transition-all"
                value={newPassword} onChange={e => setNewPassword(e.target.value)}
              />
            </div>

            <button 
              type="submit" disabled={isLoading}
              className="w-full md:w-auto px-8 py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-semibold transition-all shadow-lg shadow-indigo-600/20 disabled:opacity-50"
            >
              {isLoading ? 'Updating...' : 'Update Password'}
            </button>
          </form>
        </div>

        {/* Preferences */}
        <div className="glass-card">
          <div className="flex items-center gap-3 mb-8">
            <div className="p-2 bg-pink-500/10 rounded-lg text-pink-400">
              <Palette size={22} />
            </div>
            <div>
              <h2 className="text-xl font-bold">Preferences</h2>
              <p className="text-sm text-gray-400">Customize your VibeFlow experience.</p>
            </div>
          </div>

          <div className="flex items-center justify-between p-5 bg-white/5 rounded-xl border border-white/5">
            <div className="flex items-center gap-3">
              <Globe size={18} className="text-gray-400" />
              <div>
                <p className="font-medium">Interface Language</p>
                <p className="text-xs text-gray-500">Choose your preferred language.</p>
              </div>
            </div>
            <select className="bg-white/10 border border-white/10 rounded-lg px-4 py-2 text-sm text-white outline-none focus:ring-2 focus:ring-pink-500/50">
              <option>English</option>
              <option>Spanish</option>
              <option>French</option>
              <option>German</option>
            </select>
          </div>
        </div>

        {/* Danger Zone */}
        <div className="p-8 rounded-2xl border border-red-500/20 bg-red-500/5 flex flex-col md:flex-row items-start md:items-center justify-between gap-6">
          <div>
            <div className="flex items-center gap-2 text-xl font-bold text-red-500 mb-1">
              <Trash2 size={20} />
              Delete Account
            </div>
            <p className="text-sm text-gray-400">Permanently remove your account and all data.</p>
          </div>
          
          {showDeleteConfirm ? (
            <div className="flex items-center gap-4 animate-in fade-in slide-in-from-right-4 duration-300">
              <button onClick={handleDeleteAccount} className="px-6 py-2.5 bg-red-600 hover:bg-red-700 text-white rounded-xl font-bold transition-all shadow-lg shadow-red-600/20">
                Yes, Delete
              </button>
              <button onClick={() => setShowDeleteConfirm(false)} className="px-6 py-2.5 bg-white/5 text-gray-300 hover:text-white rounded-xl font-bold transition-all">
                Cancel
              </button>
            </div>
          ) : (
            <button 
              onClick={() => setShowDeleteConfirm(true)}
              className="px-8 py-2.5 border border-red-500/30 text-red-500 hover:bg-red-500/10 rounded-xl font-bold transition-all"
            >
              Delete Account
            </button>
          )}
        </div>
      </div>
    </div>
  );

}
